        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IGetDoubleEntryTransactionApiResponse"/>?&gt;</returns>
        Task<IGetDoubleEntryTransactionApiResponse?> GetDoubleEntryTransactionOrDefaultAsync(string bankid, string accountid, string viewid, string transactionid, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
        /// Get Firehose Transactions for Account
        /// </summary>
        /// <remarks>
